tools.handler:
var token = getVar('github_token');
var state = args.state || 'open';
var perPage = args.per_page || 10;
var url = 'https://api.github.com/repos/' + args.repo + '/issues?state=' + state + '&per_page=' + perPage;
if (args.labels) url += '&labels=' + encodeURIComponent(args.labels);
var resp = httpGet(url, {'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'AT-Skill'});
var issues = resp.body.map(function(i) {
  return {number: i.number, title: i.title, state: i.state, user: i.user.login, labels: i.labels.map(function(l){return l.name;}), created_at: i.created_at, url: i.html_url};
});
return JSON.stringify(issues, null, 2);

var token = getVar('github_token');
var payload = {title: args.title};
if (args.body) payload.body = args.body;
if (args.labels) payload.labels = args.labels;
var resp = httpPost('https://api.github.com/repos/' + args.repo + '/issues', JSON.stringify(payload), {'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json', 'User-Agent': 'AT-Skill'});
var issue = resp.body;
return JSON.stringify({number: issue.number, title: issue.title, url: issue.html_url}, null, 2);

var token = getVar('github_token');
var resp = httpPost('https://api.github.com/repos/' + args.repo + '/issues/' + args.issue_number + '/comments', JSON.stringify({body: args.body}), {'Authorization': 'token ' + token, 'Accept': 'application/vnd.github.v3+json', 'Content-Type': 'application/json', 'User-Agent': 'AT-Skill'});
var comment = resp.body;
return JSON.stringify({id: comment.id, url: comment.html_url}, null, 2);
